class InMemoryRequestStore:
    def __init__(self):
        self._store: Dict[str, Dict[str, Any]] = {}

    def create(self, relay_state: Optional[str] = None, ttl_seconds: int = 600) -> str:
        req_id = "_" + secrets.token_hex(20)
        expires_at = (_utcnow() + dt.timedelta(seconds=ttl_seconds)).timestamp()
        self._store[req_id] = {"relay_state": relay_state, "expires_at": expires_at}
        return req_id

    def get(self, request_id: str) -> Optional[Dict[str, Any]]:
        item = self._store.get(request_id)
        if not item:
            return None
        if item["expires_at"] < _utcnow().timestamp():
            self._store.pop(request_id, None)
            return None
        return item

    def pop(self, request_id: str) -> Optional[Dict[str, Any]]:
        item = self.get(request_id)
        self._store.pop(request_id, None)
        return item


class SamlAuthenticator:
    def __init__(self, sp: SamlServiceProvider, request_store: Optional[InMemoryRequestStore] = None):
        self.sp = sp
        self.request_store = request_store or InMemoryRequestStore()

    def begin_login(
        self,
        idp_sso_url: str,
        relay_state: Optional[str] = None,
        force_authn: bool = False,
        is_passive: bool = False,
        nameid_format: Optional[str] = None,
    ) -> Dict[str, str]:
        request_id = self.request_store.create(relay_state=relay_state)
        authn = self.sp.create_authn_request(
            idp_sso_url=idp_sso_url,
            relay_state=relay_state,
            force_authn=force_authn,
            is_passive=is_passive,
            nameid_format=nameid_format,
            request_id=request_id,
        )
        return authn

    def complete_login(self, saml_response_b64: str) -> Tuple[SamlUser, Optional[str]]:
        xml_bytes = _b64decode(saml_response_b64)
        parser = etree.XMLParser(resolve_entities=False, no_network=True, remove_comments=False)
        root = etree.fromstring(xml_bytes, parser=parser)
        in_response_to = root.get("InResponseTo")
        if not in_response_to:
            raise SamlValidationError("Missing InResponseTo in SAML Response")
        req = self.request_store.pop(in_response_to)
        if not req:
            raise SamlValidationError("Unknown or expired InResponseTo")
        user = self.sp.parse_response_xml(xml_bytes, expected_in_response_to=in_response_to)
        return user, req.get("relay_state")


